```class Solution {
public:
    int strangePrinter(string s) {
        int n = s.length();
        int minTurns = n;
        for (int i = 1; i < n; i++) {
            if (s[i - 1] != s[i]) {
                minTurns--;
            }
        }
        return minTurns;
    }
};```

